(function (wp, $) {
  'use strict';

  // upload btn
  var media;
  $(document).on('click', '.upload-btn', function (e) {
      e.preventDefault();
      if (media) {
          media.open();
          return;
      }
      var that = $(this);
      media = wp.media({title: 'Choose an image', multiple: false})
      .open()
      .on('select', function () {
          var obj = media.state().get('selection').first().toJSON();
          if(obj.type == 'image'){
            var thumbnail = obj.sizes.thumbnail || obj.sizes.full;
            that.siblings('img').attr('src', thumbnail.url);
            that.prev().val(obj.id);
          }else{
            that.siblings('input').val(obj.url);
          }
      });
  });

  // orderby
  function hook_orderby(data){
    var d = [
        { label: 'User', value: 'user' },
        { label: 'User played', value: 'user_played' },
        { label: 'User likes', value: 'user_likes' },
        { label: 'User following', value: 'user_following' },
        { label: 'User verified', value: 'user_verified' },
        { label: 'All count', value: 'all' },
        ];

    if(typeof count_play !== 'undefined'){
      if(count_play.indexOf('year') !== -1){
        d.push({ label: 'Yearly count', value: 'year' });
      }
      if(count_play.indexOf('month') !== -1){
        d.push({ label: 'Monthly count', value: 'month' });
      }
      if(count_play.indexOf('week') !== -1){
        d.push({ label: 'Weekly count', value: 'week' });
      }
      if(count_play.indexOf('day') !== -1){
        d.push({ label: 'Daily count', value: 'day' });
      }
    };

    d = wp.hooks.applyFilters('hook_loop_orderby', d);
    data = data.concat(d);
    return data;
  }
  (typeof wp !== 'undefined' ) && (typeof wp.hooks !== 'undefined' ) && wp.hooks.addFilter('hook_orderby', 'loopblock', hook_orderby);

  // play on button
  if(wp.element){
    var el = wp.element.createElement;
    var TextControl = wp.components.TextControl;
    var TabPanel = wp.components.TabPanel;
    var PanelBody = wp.components.PanelBody;
    var addFilter = wp.hooks.addFilter;
    var registerBlockType = wp.blocks.registerBlockType;
    var __ = wp.i18n.__;

    // bind play id on button
    var allowedPlayBlocks = [ 'core/button' ];
    addFilter(
      'blocks.registerBlockType',
      'play-block/add-attributes',
      (props, name) => {
        if( !allowedPlayBlocks.includes( name ) ){
          return props;
        }
        const attributes = {
          ...props.attributes,
          play: {
            type: 'object',
            default: {},
          }
        }
        return {...props, attributes}
      }
    )
    addFilter(
      'blocks.getSaveContent.extraProps',
      'play-block/applyExtraProps',
      (extraProps, blockType, attributes) => {
        if( !allowedPlayBlocks.includes( blockType.name ) ){
          return extraProps;
        }

        if(attributes.play.id){
          extraProps['data-btn-play'] = true;
          extraProps['data-play-id'] = attributes.play.id;
        }

        return extraProps;
      }
    );
    
    var playInspectorControls = wp.compose.createHigherOrderComponent( function ( BlockEdit ) {
        return function ( props ) {
            if( !allowedPlayBlocks.includes( props.name ) ){
              return el(
                wp.element.Fragment,
                {},
                el( BlockEdit, props )
              );
            }

            const {attributes, setAttributes, isSelected} = props;

            return el(
                wp.element.Fragment,
                {},
                el( BlockEdit, props ),
                isSelected && el(
                  wp.blockEditor.InspectorControls,
                  {},
                  el( wp.components.PanelBody
                    ,{title: 'Play', initialOpen: false, className: 'block-editor-block-inspectors'}
                    ,el(TextControl, {
                      label: __('Play post ID'),
                      value: attributes.play.id,
                      type: 'number',
                      onChange: function (id) {
                        setAttributes({play: {...attributes.play, id}})
                      }
                    })
                  )
                )
            );
        };
    }, 'withInspectorControls' );
    addFilter(
      'editor.BlockEdit',
      'play-block/with-inspector-controls',
      playInspectorControls
    );
  }

})(window.wp, jQuery);
